function editTable(gs){if(view==='done')gs=gs.filter(g=>smap(scoped.send,g.poolKey)>0);const shown=gs.slice((page-1)*pageSize,page*pageSize),disabled=!receiver;let h='<thead><tr><th>#</th><th>แบรนด์/ไซซ์</th><th>SKU</th><th>สินค้า</th><th>จำนวนออเดอร์รวม</th><th>จำนวนส่งร้านนี้</th><th>ของใส่เพิ่ม</th><th>ของดึงออก</th><th>คงเหลือรวม</th><th>ยอด</th></tr></thead><tbody>';if(!receiver&&view!=='done')h+='<tr><td colspan="10" class="empty need-recv">กรุณาเลือกร้านจริงก่อนใส่จำนวนส่ง รายการด้านล่างคือ pool รวมจาก PS/วันที่</td></tr>';shown.forEach((g,i)=>{const k=rkey(g.poolKey),r=remain(g);h+=`<tr><td>${(page-1)*pageSize+i+1}</td><td>${E(g.brand)}<br><small>${E(g.size)} · ${E(g.type)}</small></td><td>${E(g.code||'-')}</td><td class="p"><b>${E(g.sku)}</b><small>คีย์จาก ${F(g.stores.size)} ร้าน · ${F(g.bills.size)} บิล</small></td><td>${F(g.qty)}</td><td><input ${disabled?'disabled':''} class="pick jdata" data-map="send" data-k="${E(k)}" value="${recvVal(send,g)||''}" inputmode="numeric" type="number"></td><td><input ${disabled?'disabled':''} class="pick jdata" data-map="add" data-k="${E(k)}" value="${recvVal(add,g)||''}" inputmode="numeric" type="number"></td><td><input ${disabled?'disabled':''} class="pick jdata" data-map="pull" data-k="${E(k)}" value="${recvVal(pull,g)||''}" inputmode="numeric" type="number"></td><td class="${r<0?'bad':'good'}">${F(r)}</td><td>${B(g.amt)}</td></tr>`});if(!shown.length)h+='<tr><td colspan="10" class="empty">ไม่พบข้อมูล</td></tr>';return{html:h+'</tbody>',total:gs.length,label:'JSON/index ใส่ออเดอร์ให้ร้านจริง: '+(receiver||'ยังไม่เลือกร้าน')+' · '+F(gs.length)+' รายการ'}}
