function bindOnce(){if(window.__jsonBind265)return;window.__jsonBind265=true;$('#modePick')&&( $('#modePick').onclick=()=>{view='pick';page=1;render()} );$('#distTab')&&( $('#distTab').onclick=()=>{view='dist';page=1;render()} );$('#shipTab')&&( $('#shipTab').onclick=()=>{view='ship';page=1;setTabs();preparePrint()} );$('#doneTab')&&( $('#doneTab').onclick=()=>{view='done';page=1;render()} );$('#rawTab')&&( $('#rawTab').onclick=()=>{view='raw';page=1;render()} );$('#searchBtn')&&( $('#searchBtn').onclick=()=>{filters.q=$('#q')?.value||'';page=1;render()} );['startDate','endDate','psSelect','brandSelect','typeSelect'].forEach(id=>{const el=$('#'+id);if(el)el.onchange=e=>{const map={startDate:'start',endDate:'end',psSelect:'ps',brandSelect:'brand',typeSelect:'type'};pushUndo();filters[map[id]]=e.target.value;page=1;render()}});$('#storeSelect')&&( $('#storeSelect').onchange=e=>{pushUndo();receiver=e.target.value;page=1;render()} );$('#clearFilter')&&( $('#clearFilter').onclick=()=>{pushUndo();receiver='';filters={start:'',end:'',ps:'',brand:'',type:'',q:''};const ds=dates();filters.start=ds[0]||'';filters.end=ds[ds.length-1]||'';page=1;render()} );$('#displayBtn')&&( $('#displayBtn').onclick=()=>{pageSize=pageSize===80?200:80;page=1;render()} );$('#resetDone')&&( $('#resetDone').onclick=()=>{pushUndo();send={};add={};pull={};render()} );$('#undo')&&( $('#undo').onclick=doUndo );$('#redo')&&( $('#redo').onclick=doRedo );$('#copySummary')&&( $('#copySummary').onclick=copyText );$('#exportCsv')&&( $('#exportCsv').onclick=exportCsv );$('#prepPrint')&&( $('#prepPrint').onclick=preparePrint )}
